import { useState } from "react";
import { motion } from "framer-motion";
import SEOHead from "@/components/SEOHead";
import AdPlaceholder from "@/components/AdPlaceholder";
import RelatedTools from "@/components/RelatedTools";
import ShareButton from "@/components/ShareButton";
import SliderInput from "@/components/SliderInput";
import FAQItem from "@/components/FAQItem";
import { formatCurrencyValue, useCurrencyVersion } from "@/lib/currency";

const FAQS = [
  { q: "How do I calculate my car's MPG?", a: "Fill your tank completely. Reset the trip odometer. Drive normally. Fill the tank again and note how many gallons it took. MPG = miles driven  x  gallons used. For example: 350 miles  x  12 gallons = 29.2 MPG." },
  { q: "What is a good MPG for a car?", a: "For a sedan or small car, 30-40 MPG is good. SUVs average 20-30 MPG. Trucks average 15-25 MPG. Hybrid vehicles often exceed 50 MPG. Electric vehicles are rated in MPGe (miles per gallon equivalent)." },
  { q: "How can I improve my car's MPG?", a: "Keep tires properly inflated, use the recommended motor oil, remove excess weight, maintain a steady speed on highways, avoid excessive idling, and keep your engine tuned. Air conditioning can reduce MPG by 5-25%." },
  { q: "What is the difference between city and highway MPG?", a: "City MPG is lower because of frequent stops and starts that waste fuel. Highway MPG is higher because engines run at steady efficient speeds. The EPA tests both and provides a combined estimate." },
  { q: "How do I convert MPG to L/100km?", a: "Use the formula: L/100km = 235.215  x  MPG. For example, 30 MPG = 235.215  x  30 = 7.84 L/100km. The conversion factor 235.215 comes from the number of miles per liter multiplied by 100." },
  { q: "How much does it cost to drive 100 miles?", a: "Cost per 100 miles = (100  x  MPG)  x  Gas Price. For a 30 MPG car at $3.50/gallon: (100  x  30)  x  $3.50 = $11.67 per 100 miles." },
  { q: "Does air conditioning reduce fuel economy?", a: "Yes. Air conditioning can reduce fuel economy by 5-25% depending on driving conditions. City driving shows the largest reduction because the AC compressor load is more significant at lower speeds. On highways, the impact is smaller." },
];

export default function GasMileageCalculator() {
  useCurrencyVersion();
  const [miles, setMiles] = useState(350);
  const [gallons, setGallons] = useState(12);
  const [pricePerGallon, setPricePerGallon] = useState(3.50);

  const mpg = miles / gallons;
  const costPerMile = pricePerGallon / mpg;
  const costPer100Miles = costPerMile * 100;
  const lper100km = 235.215 / mpg;
  const kmPerLiter = mpg * 0.425144;
  const monthlyMiles = 1200;
  const monthlyCost = (monthlyMiles / mpg) * pricePerGallon;

  return (
    <>
      <SEOHead
        title="Free Gas Mileage Calculator Online - Calculate Your Car MPG Instantly | CalcHive"
        description="Free online gas mileage calculator. Calculate your car's fuel economy and MPG from miles driven and gallons used instantly. 100% free for everyone, no signup required."
        canonical="/gas-mileage-calculator"
        keywords="free gas mileage calculator, MPG calculator free online, fuel economy calculator free, calculate car MPG free, miles per gallon calculator free"
        category="Automotive Calculators"
        faqs={FAQS}
      />
      <main className="max-w-3xl mx-auto px-4 sm:px-6 py-10">
        <div className="mb-8">
          <span className="text-xs font-semibold uppercase tracking-widest text-rose-600 dark:text-rose-400 bg-rose-50 dark:bg-rose-950/50 px-3 py-1 rounded-full mb-4 inline-block">Transportation</span>
          <h1 className="text-3xl sm:text-4xl font-extrabold text-foreground tracking-tight mb-3">Free Gas Mileage Calculator Online</h1>
          <p className="text-muted-foreground leading-relaxed">Use this free gas mileage calculator to calculate car MPG free from miles driven and gallons used. This MPG calculator free online also works as a fuel economy calculator free and miles per gallon calculator free for every driver.</p>
        </div>
        <AdPlaceholder size="banner" className="mb-8" />
        <section className="bg-card border border-border rounded-2xl p-6 sm:p-8 shadow-md mb-8">
          <div className="space-y-6 mb-8">
            <SliderInput id="miles" label="Miles Driven" value={miles} min={1} max={10000} step={1} onChange={setMiles} format={v => `${v.toLocaleString()} miles`} testId="input-miles" />
            <SliderInput id="gallons" label="Gallons Used" value={gallons} min={0.1} max={100} step={0.1} onChange={setGallons} format={v => `${v.toFixed(1)} gal`} testId="input-gallons" />
            <SliderInput id="price" label="Gas Price" value={pricePerGallon} min={0.50} max={8} step={0.01} onChange={setPricePerGallon} format={v => `${formatCurrencyValue(v)}/gal`} testId="input-price" />
          </div>
          <motion.div key={`${miles}-${gallons}-${pricePerGallon}`} initial={{ opacity: 0.7, y: 4 }} animate={{ opacity: 1, y: 0 }} transition={{ duration: 0.25 }}>
            <div className="bg-gradient-to-br from-rose-500 to-rose-700 rounded-2xl p-6 mb-4 text-center shadow-lg">
              <p className="text-xs font-semibold uppercase tracking-widest text-white/70 mb-1">Fuel Economy</p>
              <p className="text-6xl font-black text-white tracking-tight" data-testid="result-mpg">{mpg.toFixed(1)} MPG</p>
              <p className="text-white/70 text-sm mt-1">{lper100km.toFixed(1)} L/100km - {kmPerLiter.toFixed(1)} km/L</p>
            </div>
            <div className="grid grid-cols-2 sm:grid-cols-4 gap-3">
              {[
                { label: "MPG", value: mpg.toFixed(2) },
                { label: "L/100km", value: lper100km.toFixed(2) },
                { label: "Cost/Mile", value: formatCurrencyValue(costPerMile, { minimumFractionDigits: 3, maximumFractionDigits: 3 }) },
                { label: "Cost/100 Miles", value: formatCurrencyValue(costPer100Miles) },
              ].map(({ label, value }) => (
                <div key={label} className="bg-accent/60 border border-border rounded-xl p-4 text-center">
                  <p className="text-xs text-muted-foreground font-medium mb-1">{label}</p>
                  <p className="text-base font-extrabold text-foreground">{value}</p>
                </div>
              ))}
            </div>
          </motion.div>
        </section>
        <ShareButton />

        <section className="mb-8 space-y-6">
          <h2 className="text-2xl font-bold text-foreground">How to Calculate Your Car's MPG for Free</h2>
          <p className="text-muted-foreground leading-relaxed">MPG (miles per gallon) is measured from a full tank to the next fill-up: divide the miles you drove by the gallons needed to refill. For the most accurate reading, use consecutive fill-ups and make sure you top off fully both times.</p>
          <div className="bg-accent/60 border border-border rounded-2xl p-5 font-mono text-sm text-foreground space-y-1">
            <p>MPG = Miles Driven  x  Gallons Used</p>
            <p>L/100km = 235.215  x  MPG</p>
            <p>Cost Per Mile = Gas Price  x  MPG</p>
            <p>Monthly Fuel Cost = Monthly Miles  x  MPG  x  Gas Price</p>
          </div>

          <h2 className="text-2xl font-bold text-foreground">How to Measure Your Vehicle's Fuel Economy</h2>
          <div className="overflow-x-auto">
            <table className="w-full text-sm border border-border rounded-xl overflow-hidden">
              <thead className="bg-muted/60">
                <tr>
                  {["Vehicle Type", "City MPG", "Highway MPG", "Combined MPG", "L/100km"].map(h => <th key={h} className="text-left py-3 px-3 font-semibold text-foreground">{h}</th>)}
                </tr>
              </thead>
              <tbody className="divide-y divide-border">
                {[
                  ["Compact Sedan", "28-34", "38-45", "32-38", "7.4-6.2"],
                  ["Midsize Sedan", "24-30", "34-40", "28-34", "8.4-6.9"],
                  ["Compact SUV", "26-30", "30-38", "27-33", "8.7-7.1"],
                  ["Midsize SUV", "18-25", "24-32", "20-28", "11.8-8.4"],
                  ["Full-Size Truck", "14-20", "18-26", "15-22", "15.7-10.7"],
                  ["Hybrid Sedan", "40-55", "40-55", "42-55", "5.6-4.3"],
                  ["Plug-in Hybrid", "50-90 MPGe", "45-80 MPGe", "50-85 MPGe", "~4.7-2.8"],
                  ["Electric Vehicle", "90-140 MPGe", "90-130 MPGe", "95-135 MPGe", "N/A (kWh/100mi)"],
                ].map(([type, city, hwy, combined, lper100]) => (
                  <tr key={type} className="hover:bg-muted/30">
                    <td className="py-2.5 px-3 font-semibold text-foreground">{type}</td>
                    <td className="py-2.5 px-3 text-muted-foreground">{city}</td>
                    <td className="py-2.5 px-3 text-muted-foreground">{hwy}</td>
                    <td className="py-2.5 px-3 text-rose-600 dark:text-rose-400 font-medium">{combined}</td>
                    <td className="py-2.5 px-3 text-muted-foreground">{lper100}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>

          <h2 className="text-2xl font-bold text-foreground">Free MPG and Fuel Economy Calculator for Every Driver</h2>
          <div className="overflow-x-auto">
            <table className="w-full text-sm border border-border rounded-xl overflow-hidden">
              <thead className="bg-muted/60">
                <tr>
                  {["Monthly Miles", `At ${formatCurrencyValue(pricePerGallon - 0.5)}/gal`, `At ${formatCurrencyValue(pricePerGallon)}/gal (current)`, `At ${formatCurrencyValue(pricePerGallon + 0.5)}/gal`].map(h => <th key={h} className="text-left py-3 px-3 font-semibold text-foreground">{h}</th>)}
                </tr>
              </thead>
              <tbody className="divide-y divide-border">
                {[500, 1000, 1200, 1500, 2000, 2500].map(mi => (
                  <tr key={mi} className={`hover:bg-muted/30 ${mi === 1200 ? "bg-rose-50 dark:bg-rose-950/20" : ""}`}>
                    <td className="py-2.5 px-3 font-semibold text-foreground">{mi.toLocaleString()} mi</td>
                    {[pricePerGallon - 0.5, pricePerGallon, pricePerGallon + 0.5].map(p => (
                      <td key={p} className="py-2.5 px-3 text-muted-foreground">{formatCurrencyValue((mi / mpg) * p)}</td>
                    ))}
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </section>

        <section className="mb-8">
          <h3 className="text-xl font-bold text-foreground mb-4">Frequently Asked Questions</h3>
          <div className="space-y-3">{FAQS.map(f => <FAQItem key={f.q} q={f.q} a={f.a} />)}</div>
        </section>
        <AdPlaceholder size="rectangle" className="mx-auto mb-8" />
        <RelatedTools exclude="/gas-mileage-calculator" headingLevel="h3" />
      </main>
    </>
  );
}


